import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: (project_basename, framework, package_id) -> resolvedVersion
def build_lookup(data):
    lookup = {}
    for p in data['projects']:
        proj = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                lookup[(proj, fw['framework'], pkg['id'])] = pkg['resolvedVersion']
    return lookup

b = build_lookup(baseline)
a = build_lookup(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))

changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv == av:
        unchanged.append((k[0], k[2], k[1], av))
    else:
        changes.append((k[0], k[2], k[1], bv or '(none)', av or '(none)'))

print('=== CHANGES ===')
for c in changes:
    print(f'{c[0]:20s} {c[1]:45s} {c[2]:10s} {c[3]:10s} -> {c[4]:10s}')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'{u[0]:20s} {u[1]:45s} {u[2]:10s} {u[3]:10s}')
