import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def build_lookup(data):
    lookup = {}
    for p in data['projects']:
        proj = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                lookup[(proj, fw['framework'], pkg['id'])] = pkg['resolvedVersion']
    return lookup

b = build_lookup(baseline)
a = build_lookup(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))

changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv == av:
        unchanged.append(k + (av,))
    else:
        changes.append(k + (bv or '(none)', av or '(none)'))

print('=== CHANGES ===')
if not changes:
    print('(none)')
else:
    print(f'{\"Project\":<18s} {\"Framework\":<10s} {\"Package\":<45s} {\"Before\":<12s} {\"After\":<12s}')
    for c in changes:
        print(f'{c[0]:<18s} {c[1]:<10s} {c[2]:<45s} {c[3]:<12s} {c[4]:<12s}')

print()
