print(f'{\"Project\":<18s} {\"Framework\":<10s} {\"Package\":<45s} {\"Version\":<12s}')
for u in unchanged:
    print(f'{u[0]:<18s} {u[1]:<10s} {u[2]:<45s} {u[3]:<12s}')
